#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t R,G,B,K; scanf("%" PRId64 " %" PRId64 " %" PRId64, &R,&G,&B);
        scanf("%" PRId64, &K);
        int64_t limit = K-1;
        int64_t sum = (R<limit?R:limit) + (G<limit?G:limit) + (B<limit?B:limit);
        printf("%" PRId64 "\n", sum+1);
    }
    return 0;
}

